/**
 * Seed features and plans.
 *
 * @param force  When true, overwrite existing documents with the definitions
 *               above. Destroys operator pricing changes — intended for local
 *               development and CI only. NEVER pass true against production.
 */
export async function seedBillingData(force = false): Promise<void> {
  console.log('[BillingSeed] Seeding feature catalogue...');

  for (const feature of FEATURES) {
    if (force) {
      await Feature.findOneAndUpdate({ key: feature.key }, { $set: feature }, { upsert: true });
    } else {
      // $setOnInsert leaves an existing document completely untouched, so a
      // re-run after an operator edited descriptions is safe.
      await Feature.findOneAndUpdate(
        { key: feature.key },
        { $setOnInsert: { ...feature, isActive: true } },
        { upsert: true, setDefaultsOnInsert: true }
      );
    }
  }
  console.log(`[BillingSeed] ${FEATURES.length} features ready.`);

  console.log('[BillingSeed] Seeding subscription plans...');
  for (const plan of PLANS) {
    if (force) {
      await SubscriptionPlan.findOneAndUpdate({ code: plan.code }, { $set: plan }, { upsert: true });
      console.log(`[BillingSeed]   ${plan.code} — overwritten`);
    } else {
      const existing = await SubscriptionPlan.findOne({ code: plan.code }).select('_id').exec();
      if (existing) {
        console.log(`[BillingSeed]   ${plan.code} — already exists, left unchanged`);
        continue;
      }
      await SubscriptionPlan.create({ ...plan, isActive: true });
      console.log(`[BillingSeed]   ${plan.code} — created`);
    }
  }

  planRepository.invalidate();
  console.log('[BillingSeed] Done.');
}
